function MovieRow({ title, movies }) {
  if (!movies || movies.length === 0) return null;

  return (
    <div className="movie-row">
      <h2>{title}</h2>
      <div className="row">
        {movies.slice(0, 10).map((movie) => (
          <div key={movie.id} className="card">
            <img
              src={movie.image || ""}
              alt={movie.title}
            />
          </div>
        ))}
      </div>
    </div>
  );
}
export default MovieRow;
